import{_ as t,a,b as o,c as n,d as i}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as r,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Adding a OneDrive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/onedrive.md","filePath":"en/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"en/upload/onedrive.md"};function p(h,e,u,f,m,g){return d(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="adding-a-onedrive-channel" tabindex="-1">Adding a OneDrive Channel <a class="header-anchor" href="#adding-a-onedrive-channel" aria-label="Permalink to &quot;Adding a OneDrive Channel&quot;">​</a></h1><h2 id="what-you-need-first" tabindex="-1">What You Need First <a class="header-anchor" href="#what-you-need-first" aria-label="Permalink to &quot;What You Need First&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Why You Need It</th></tr></thead><tbody><tr><td>A Microsoft account</td><td>Used to access Microsoft admin pages and authorize OneDrive</td></tr><tr><td>Your ImgBed domain</td><td>Used for the OAuth callback URL</td></tr><tr><td>An app registration</td><td>Used to generate the <code>Client ID</code> and <code>Client Secret</code></td></tr><tr><td>A OneDrive account</td><td>Used as the actual file storage location</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-open-microsoft-entra-id" tabindex="-1">Step 1: Open Microsoft Entra ID <a class="header-anchor" href="#step-1-open-microsoft-entra-id" aria-label="Permalink to &quot;Step 1: Open Microsoft Entra ID&quot;">​</a></h3><ol><li>Open <code>portal.azure.com</code>.</li><li>Search for <code>Microsoft Entra ID</code> at the top.</li><li>If the target page is not shown in the dropdown, choose:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Open <code>Microsoft Entra ID</code>.</li><li>Open <code>App registrations</code>.</li><li>Click <code>New registration</code>.</li></ol><h3 id="step-2-register-an-app" tabindex="-1">Step 2: Register an App <a class="header-anchor" href="#step-2-register-an-app" aria-label="Permalink to &quot;Step 2: Register an App&quot;">​</a></h3><p>On the <code>New registration</code> page, fill in:</p><table tabindex="0"><thead><tr><th>Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Name</td><td>A recognizable name, such as <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Choose based on the table below</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Account type guidance:</p><table tabindex="0"><thead><tr><th>Your Scenario</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Personal OneDrive only</td><td>Choose the personal Microsoft account option.</td></tr><tr><td>Both personal and work/school accounts</td><td>Choose the option that supports both personal and organizational accounts.</td></tr><tr><td>Company or school OneDrive only</td><td>Choose the organizational account option.</td></tr></tbody></table><p>Click register after filling in the form.</p><p><img src="'+t+'" alt="Create OneDrive app" loading="lazy"></p><h3 id="step-3-copy-app-information" tabindex="-1">Step 3: Copy App Information <a class="header-anchor" href="#step-3-copy-app-information" aria-label="Permalink to &quot;Step 3: Copy App Information&quot;">​</a></h3><p>After the app is created, copy these values from the overview page:</p><table tabindex="0"><thead><tr><th>Microsoft Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> for organizational accounts</td></tr></tbody></table><p><img src="'+a+'" alt="Application and tenant IDs" loading="lazy"></p><h3 id="step-4-create-a-client-secret" tabindex="-1">Step 4: Create a Client Secret <a class="header-anchor" href="#step-4-create-a-client-secret" aria-label="Permalink to &quot;Step 4: Create a Client Secret&quot;">​</a></h3><ol><li>Open <code>Certificates &amp; secrets</code>.</li><li>Click <code>New client secret</code>.</li><li>Enter any description you prefer.</li><li>Choose an expiration period.</li><li>Copy the <code>Value</code> immediately after it is created.</li></ol><p><img src="'+o+'" alt="Save client secret value" loading="lazy"></p><h3 id="step-5-add-api-permissions" tabindex="-1">Step 5: Add API Permissions <a class="header-anchor" href="#step-5-add-api-permissions" aria-label="Permalink to &quot;Step 5: Add API Permissions&quot;">​</a></h3><ol><li>Open <code>API permissions</code>.</li><li>Click <code>Add a permission</code>.</li><li>Choose <code>Microsoft Graph</code>.</li><li>Choose <code>Delegated permissions</code>.</li><li>Add these permissions:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Uploads files, creates folders, and deletes files</td></tr><tr><td><code>offline_access</code></td><td>Allows ImgBed to obtain a <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Reads account and quota information</td></tr></tbody></table><h3 id="step-6-fill-in-the-onedrive-channel" tabindex="-1">Step 6: Fill in the OneDrive Channel <a class="header-anchor" href="#step-6-fill-in-the-onedrive-channel" aria-label="Permalink to &quot;Step 6: Fill in the OneDrive Channel&quot;">​</a></h3><p>In Upload Settings, choose <code>OneDrive</code> and fill in:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A recognizable name, such as <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>The Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>The <code>Client Secret Value</code> you copied</td></tr><tr><td>Tenant ID</td><td>Use the table below</td></tr><tr><td>Refresh Token</td><td>Leave it empty for now</td></tr><tr><td>Root directory</td><td>Optional. Defaults to <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+n+'" alt="Fill OneDrive channel config" loading="lazy"></p><p>How to fill <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Account Type You Chose</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>Current organization only</td><td>The <code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="step-7-get-the-refresh-token" tabindex="-1">Step 7: Get the Refresh Token <a class="header-anchor" href="#step-7-get-the-refresh-token" aria-label="Permalink to &quot;Step 7: Get the Refresh Token&quot;">​</a></h3><ol><li>In ImgBed, click <code>Get Token</code>.</li><li>Sign in to the Microsoft account you want to connect.</li><li>Approve the authorization prompt.</li><li>The callback page will show a <code>Refresh Token</code>.</li><li>Copy it.</li><li>Return to ImgBed and paste it into the <code>Refresh Token</code> field.</li></ol><p><img src="'+i+`" alt="Copy refresh token" loading="lazy"></p><h3 id="step-8-save-the-channel" tabindex="-1">Step 8: Save the Channel <a class="header-anchor" href="#step-8-save-the-channel" aria-label="Permalink to &quot;Step 8: Save the Channel&quot;">​</a></h3><p>After all fields are filled in, save the channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open portal.azure.com</span></span>
<span class="line"><span>-&gt; Search for Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Open App registrations</span></span>
<span class="line"><span>-&gt; Register a new app</span></span>
<span class="line"><span>-&gt; Fill Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; Copy Application (client) ID</span></span>
<span class="line"><span>-&gt; Check the callback URL in Authentication</span></span>
<span class="line"><span>-&gt; Create a Client Secret in Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Add permissions in API permissions</span></span>
<span class="line"><span>-&gt; Fill Client ID / Client Secret / Tenant ID into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const C=r(c,[["render",p]]);export{k as __pageData,C as default};
